// app/api/whatsapp/sessions/[id]/qrcode/route.ts
import { NextResponse } from 'next/server'

const WACLI = process.env.WACLI_BASE_URL ?? 'http://localhost:3333'

// Tiny 1px transparent PNG as placeholder QR mock (base64)
const MOCK_QR =
  'data:image/png;base64,'

export async function GET(
  _req: Request,
  { params }: { params: Promise<{ id: string }> }
) {
  const { id } = await params
  try {
    const res = await fetch(`${WACLI}/api/sessions/${id}/qrcode`, { cache: 'no-store' })
    const data = await res.json()
    return NextResponse.json(data)
  } catch {
    return NextResponse.json({ qrcode: MOCK_QR, expired: false })
  }
}
